import React, { useState } from 'react';

const campos = [
  { name: 'CNPJ', label: 'CNPJ', required: true },
  { name: 'ANO', label: 'Ano', required: true },
  { name: 'MES', label: 'Mês', required: true },
  { name: 'COD_IBGE', label: 'Código IBGE', required: true },
  { name: 'TIPO_CLIENTE', label: 'Tipo Cliente', required: true },
  { name: 'TIPO_ATENDIMENTO', label: 'Tipo Atendimento', required: true },
  { name: 'TIPO_MEIO', label: 'Tipo Meio', required: true },
  { name: 'TIPO_PRODUTO', label: 'Tipo Produto', required: true },
  { name: 'TIPO_TECNOLOGIA', label: 'Tipo Tecnologia', required: true },
  { name: 'VELOCIDADE', label: 'Velocidade', required: true },
  { name: 'ACESSOS', label: 'Acessos', required: true },
];

function toCSV(obj) {
  const header = campos.map(c => c.name).join(';');
  const row = campos.map(c => obj[c.name] || '').join(';');
  return `${header}\n${row}`;
}

const CadastroSCM = () => {
  const [form, setForm] = useState({});
  const [csv, setCsv] = useState('');

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleGerarCSV = e => {
    e.preventDefault();
    const csvContent = toCSV(form);
    setCsv(csvContent);
    // Download automático
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.setAttribute('download', 'COLETA_SCM.csv');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div style={{maxWidth:500,margin:'2rem auto',background:'#fff',padding:24,borderRadius:12,boxShadow:'0 2px 8px #0001'}}>
      <h2>Cadastro SCM</h2>
      <form onSubmit={handleGerarCSV} style={{display:'flex',flexDirection:'column',gap:12}}>
        {campos.map(campo => (
          <div key={campo.name} style={{display:'flex',flexDirection:'column'}}>
            <label htmlFor={campo.name} style={{fontWeight:600}}>{campo.label}:</label>
            <input
              id={campo.name}
              name={campo.name}
              value={form[campo.name] || ''}
              onChange={handleChange}
              required={campo.required}
              style={{padding:8,borderRadius:4,border:'1px solid #ccc'}}
            />
          </div>
        ))}
        <button type="submit" style={{marginTop:16,background:'#1976d2',color:'#fff',border:'none',borderRadius:4,padding:'0.7rem 2rem',fontWeight:'bold',fontSize:16,cursor:'pointer'}}>Gerar CSV</button>
      </form>
      {csv && (
        <div style={{marginTop:24}}>
          <h4>Prévia do CSV:</h4>
          <pre style={{background:'#eee',padding:12,borderRadius:6}}>{csv}</pre>
        </div>
      )}
    </div>
  );
};

export default CadastroSCM;
